window.GS_CODE = "// ── 中台禪寺各精舍貴賓管理系統 — Apps Script 後端 ──────────────────\n// 這個檔案負責：\n//   1. 提供網頁（doGet）\n//   2. 讀取雲端資料（gsLoad）\n//   3. 儲存雲端資料（gsSave）\n// 資料存在此帳號的 Google Drive，檔名為 vip_sync_data.json\n\nconst DATA_FILE = 'vip_sync_data.json';\n\nfunction doGet() {\n  return HtmlService.createHtmlOutputFromFile('index')\n    .setTitle('中台禪寺各精舍 貴賓管理系統')\n    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL);\n}\n\nfunction gsLoad() {\n  try {\n    const files = DriveApp.getFilesByName(DATA_FILE);\n    if (files.hasNext()) return files.next().getBlob().getDataAsString();\n    return JSON.stringify({ events: [] });\n  } catch(e) {\n    return JSON.stringify({ events: [], _error: e.message });\n  }\n}\n\nfunction gsSave(jsonStr) {\n  try {\n    const files = DriveApp.getFilesByName(DATA_FILE);\n    if (files.hasNext()) {\n      files.next().setContent(jsonStr);\n    } else {\n      DriveApp.createFile(DATA_FILE, jsonStr, MimeType.PLAIN_TEXT);\n    }\n    return JSON.stringify({ ok: true });\n  } catch(e) {\n    return JSON.stringify({ ok: false, error: e.message });\n  }\n}\n";
window.HTML_CODE = "<!DOCTYPE html>\n<html lang=\"zh-TW\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no\">\n  <title>中台禪寺各精舍 — 貴賓管理系統</title>\n  <script src=\"https://cdn.sheetjs.com/xlsx-0.20.3/package/dist/xlsx.full.min.js\"></script>\n  <style>\n    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n    body {\n      font-family: \"Noto Sans TC\",\"Microsoft JhengHei\",-apple-system,sans-serif;\n      background: #f4f4f4; color: #2c2c2c;\n      height: 100dvh; display: flex; flex-direction: column; overflow: hidden;\n    }\n    #app { flex:1; min-height:0; display:flex; flex-direction:column; }\n    .app-header {\n      background:#6b3d2e; color:#fff; text-align:center;\n      padding:14px 16px; font-size:17px; font-weight:bold; letter-spacing:1px; flex-shrink:0;\n    }\n    #page-content {\n      flex:1; min-height:0; overflow-y:auto; -webkit-overflow-scrolling:touch; padding:16px 16px 88px;\n    }\n    /* ── Bottom Nav ── */\n    .bottom-tab {\n      position:fixed; bottom:0; left:0; right:0; height:64px;\n      background:#fff; border-top:1px solid #e8ddd9;\n      display:flex; align-items:stretch; z-index:100; flex-shrink:0;\n    }\n    .tab-btn {\n      flex:1; display:flex; flex-direction:column; align-items:center; justify-content:center;\n      border:none; background:transparent; cursor:pointer; color:#aaa; font-size:11px; gap:3px; padding:0;\n    }\n    .tab-btn.active { color:#6b3d2e; }\n    .tab-btn svg { width:22px; height:22px; fill:none; stroke:currentColor; stroke-width:1.8; stroke-linecap:round; stroke-linejoin:round; }\n    /* ── Cards ── */\n    .event-card {\n      background:#fff; border-radius:14px; padding:16px; margin-bottom:14px;\n      box-shadow:0 1px 4px rgba(0,0,0,0.08); display:flex; align-items:center; gap:12px;\n    }\n    .event-card-main { flex:1; min-width:0; }\n    .vip-name { font-size:16px; font-weight:bold; color:#2c2c2c; }\n    .vip-meta { font-size:13px; color:#aaa; margin-top:3px; }\n    .event-card-upload {\n      background:#fff3e0; color:#e67e22; border:none; border-radius:8px;\n      padding:8px 12px; font-size:13px; font-family:inherit; cursor:pointer; white-space:nowrap; flex-shrink:0;\n    }\n    .event-card-edit {\n      background:transparent; border:none; color:#aaa; cursor:pointer; padding:4px; flex-shrink:0;\n    }\n    /* ── Buttons ── */\n    .btn-primary {\n      background:#6b3d2e; color:#fff; border:none; border-radius:10px;\n      padding:13px 20px; font-size:15px; font-family:inherit; cursor:pointer; font-weight:500;\n    }\n    .btn-primary:disabled { opacity:0.4; cursor:not-allowed; }\n    .fab {\n      position:fixed; bottom:80px; right:20px; width:52px; height:52px;\n      border-radius:50%; background:#6b3d2e; color:#fff; border:none;\n      font-size:26px; cursor:pointer; box-shadow:0 3px 12px rgba(0,0,0,0.25);\n      display:flex; align-items:center; justify-content:center; z-index:50;\n    }\n    /* ── Modal ── */\n    .modal-overlay {\n      position:fixed; inset:0; background:rgba(0,0,0,0.45); display:flex;\n      align-items:flex-end; justify-content:center; z-index:200;\n    }\n    .modal {\n      background:#fff; border-radius:20px 20px 0 0; width:100%; max-width:600px;\n      max-height:90vh; display:flex; flex-direction:column;\n    }\n    .modal-header {\n      display:flex; align-items:center; justify-content:space-between;\n      padding:16px 16px 12px; border-bottom:1px solid #f0e8e4; flex-shrink:0;\n    }\n    .modal-title { font-size:17px; font-weight:bold; color:#2c2c2c; }\n    .modal-action { background:transparent; border:none; font-size:15px; cursor:pointer; color:#888; padding:4px 8px; font-family:inherit; }\n    .modal-action.confirm { color:#6b3d2e; font-weight:bold; }\n    .modal-body { overflow-y:auto; padding:16px; flex:1; }\n    /* ── Form ── */\n    .form-group { margin-bottom:18px; }\n    .form-label { display:block; font-size:13px; font-weight:bold; color:#6b3d2e; margin-bottom:6px; }\n    .form-input {\n      width:100%; border:1px solid #e0d8d4; border-radius:10px;\n      padding:12px 14px; font-size:15px; font-family:inherit; color:#2c2c2c; background:#fff;\n    }\n    .form-input:focus { outline:none; border-color:#6b3d2e; }\n    .section-divider {\n      font-size:13px; font-weight:bold; color:#aaa; letter-spacing:0.5px;\n      margin:20px 0 10px; text-transform:uppercase;\n    }\n    /* ── Table Setting ── */\n    .table-setting-row { display:flex; align-items:center; gap:8px; margin-bottom:10px; }\n    .table-setting-label { font-size:14px; color:#666; white-space:nowrap; }\n    .table-num-input {\n      width:72px; border:1px solid #e0d8d4; border-radius:8px;\n      padding:9px 10px; font-size:15px; font-family:inherit; text-align:center;\n    }\n    .table-num-input:focus { outline:none; border-color:#6b3d2e; }\n    .table-item {\n      display:flex; align-items:center; justify-content:space-between;\n      padding:8px 12px; background:#fdf7f4; border-radius:8px; margin-bottom:6px;\n    }\n    .table-item-info { font-size:14px; color:#555; }\n    .relative-remove { background:transparent; border:none; color:#aaa; font-size:18px; cursor:pointer; line-height:1; padding:0 4px; }\n    .add-rel-form { background:#fdf7f4; border-radius:10px; padding:14px; margin-top:8px; }\n    .add-rel-btn {\n      width:100%; margin-top:10px; background:#6b3d2e; color:#fff; border:none;\n      border-radius:8px; padding:10px; font-size:14px; font-family:inherit; cursor:pointer;\n    }\n    .add-rel-btn:disabled { opacity:0.4; cursor:not-allowed; }\n    /* ── Seat Table Card ── */\n    .seat-table-card {\n      background:#fff; border-radius:14px; padding:16px; margin-bottom:14px;\n      box-shadow:0 1px 4px rgba(0,0,0,0.08);\n    }\n    .seat-table-header { display:flex; align-items:center; gap:8px; margin-bottom:10px; }\n    .seat-table-title { font-size:15px; font-weight:bold; color:#2c2c2c; flex:1; }\n    .seat-count-text { font-size:13px; color:#aaa; }\n    .seat-full-badge {\n      background:#e8f5e9; color:#27ae60; font-size:11px; font-weight:bold;\n      padding:2px 8px; border-radius:99px;\n    }\n    .seat-chips { display:flex; flex-wrap:wrap; gap:8px; }\n    .seat-chip {\n      background:#fdf7f4; border:1px solid #e8ddd9; border-radius:10px; padding:8px 12px; min-width:120px;\n    }\n    .seat-chip-row { display:flex; align-items:center; justify-content:space-between; gap:6px; }\n    .seat-chip-name { font-size:14px; font-weight:bold; color:#2c2c2c; }\n    .seat-chip-remove { background:transparent; border:none; color:#ccc; font-size:16px; cursor:pointer; line-height:1; }\n    .seat-chip-rel { font-size:12px; color:#c09070; margin-top:4px; }\n    .seat-assign-btn {\n      width:100%; background:#fdf7f4; border:1px dashed #c8b8b0; border-radius:8px;\n      padding:10px; font-size:14px; color:#6b3d2e; cursor:pointer; font-family:inherit;\n    }\n    /* ── Attend Search ── */\n    .attend-search {\n      width:100%; border:1px solid #e0d8d4; border-radius:10px;\n      padding:10px 14px; font-size:15px; font-family:inherit; margin-bottom:14px;\n    }\n    .attend-search:focus { outline:none; border-color:#6b3d2e; }\n    .vip-check-row {\n      display:flex; align-items:center; padding:12px 0;\n      border-bottom:1px solid #f5f5f5; cursor:pointer; gap:12px;\n    }\n    .empty-hint { color:#bbb; font-size:14px; text-align:center; }\n    /* ── Result ── */\n    .result-table-card {\n      background:#fff; border-radius:14px; margin-bottom:14px;\n      box-shadow:0 1px 4px rgba(0,0,0,0.08); overflow:hidden;\n    }\n    .result-table-header {\n      background:#6b3d2e; color:#fff; padding:12px 16px;\n      display:flex; align-items:center; justify-content:space-between;\n    }\n    .result-table-title { font-size:15px; font-weight:bold; }\n    .result-table-count { font-size:13px; opacity:0.8; }\n    .result-row {\n      padding:10px 16px; border-bottom:1px solid #f5f5f5;\n      display:flex; align-items:center; justify-content:space-between;\n    }\n    .result-row-name { font-size:14px; font-weight:bold; }\n    .result-row-sub { font-size:12px; color:#999; }\n    .result-row-btn { background:transparent; border:none; font-size:12px; color:#6b3d2e; cursor:pointer; }\n    /* ── Seat Note ── */\n    .seat-note-card {\n      background:#fff; border-radius:16px; overflow:hidden; width:340px; max-width:90vw;\n    }\n    .seat-note-top {\n      background:#ff7300; color:#fff; padding:14px 20px; text-align:center;\n      font-size:18px; font-weight:bold;\n    }\n    .seat-note-event { font-size:24px; color:#555; text-align:center; padding:12px 20px 4px; font-weight:500; }\n    .seat-note-subtitle { font-size:20px; color:#a07060; text-align:center; padding:0 20px 8px; }\n    .seat-note-divider { height:1px; background:#eee; margin:0 20px; }\n    .seat-note-body { padding:16px 20px; }\n    .seat-note-label { font-size:11px; color:#aaa; font-weight:bold; letter-spacing:0.5px; margin-bottom:4px; }\n    .seat-note-value { font-size:28px; font-weight:bold; color:#2c2c2c; margin-bottom:12px; }\n    .seat-note-table { font-size:22px; font-weight:bold; color:#6b3d2e; }\n    .seat-note-carno { font-size:14px; color:#888; margin-top:6px; }\n    .seat-note-actions { display:flex; gap:10px; padding:12px 16px 16px; }\n    .seat-note-actions button {\n      flex:1; border:none; border-radius:10px; padding:11px;\n      font-size:14px; font-family:inherit; cursor:pointer;\n    }\n    /* ── Misc ── */\n    .page-title { font-size:17px; font-weight:bold; color:#3d1f0f; margin-bottom:14px; }\n    .event-selector {\n      width:100%; border:1px solid #e0d8d4; border-radius:10px;\n      padding:12px 14px; font-size:15px; font-family:inherit; background:#fff; margin-bottom:16px;\n    }\n    .chevron-icon { width:18px; height:18px; stroke:#ccc; fill:none; stroke-width:2; stroke-linecap:round; stroke-linejoin:round; flex-shrink:0; }\n  </style>\n</head>\n<body>\n\n<div id=\"app\">\n  <div class=\"app-header\">中台禪寺各精舍 — 貴賓管理系統</div>\n  <div id=\"page-content\" class=\"page-content\"></div>\n  <nav class=\"bottom-tab\" id=\"bottom-tab\"></nav>\n</div>\n\n<!-- 主 Modal -->\n<div id=\"modal-overlay\" class=\"modal-overlay\" style=\"display:none\">\n  <div id=\"modal-box\" class=\"modal\"></div>\n</div>\n\n<!-- 座位小單 Modal -->\n<div id=\"note-overlay\" class=\"modal-overlay\" style=\"display:none;align-items:center;\">\n  <div id=\"note-box\" class=\"seat-note-card\"></div>\n</div>\n\n<!-- Excel 上傳 input -->\n<input type=\"file\" id=\"excel-input\" accept=\".xlsx,.xls\" style=\"display:none\">\n\n<script>\n// ═══════════════════════════════════════════════════════\n// 工具\n// ═══════════════════════════════════════════════════════\nfunction genId() { return Date.now().toString(36) + Math.random().toString(36).slice(2,6) }\nfunction esc(s) { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\"/g,'&quot;') }\nfunction fmt(s) { return esc(s) }\n\n// ═══════════════════════════════════════════════════════\n// localStorage\n// ═══════════════════════════════════════════════════════\nconst Storage = {\n  get(k,d){ try{const v=localStorage.getItem(k);return v?JSON.parse(v):d}catch{return d} },\n  set(k,v){ try{localStorage.setItem(k,JSON.stringify(v))}catch{} },\n  getEvents(){ return this.get('events',[]) },\n  saveEvents(v){ this.set('events',v) },\n}\n\n// ═══════════════════════════════════════════════════════\n// 狀態\n// ═══════════════════════════════════════════════════════\nlet S = {\n  tab: 'events',\n  events: [],\n  // 活動 Modal\n  showEventModal: false,\n  editingEventId: null,\n  tableInputMode: 'single',\n  uploadTargetId: null,\n  // 排桌\n  seatEventId: null,\n  showSeatPicker: false,\n  seatPickTable: '',\n  batchPickIds: [],\n  seatSearch: '',\n  // 親眷提示\n  showRelativePrompt: false,\n  relativeVid: null,\n  relativeCandidates: [],\n  relativeChecked: [],\n  pendingSeatKey: '',\n  // 結果\n  resultEventId: null,\n  // 小單\n  showSeatNote: false,\n  seatNoteData: {},\n  // 雲端\n  cloudStatus: '',\n  cloudSyncing: '',\n}\n\n// ═══════════════════════════════════════════════════════\n// 計算屬性（函式）\n// ═══════════════════════════════════════════════════════\nfunction seatEvent()  { return S.events.find(e=>e.id===S.seatEventId)||null }\nfunction resultEvent(){ return S.events.find(e=>e.id===S.resultEventId)||null }\n\nfunction seatMainAtts(){ return (seatEvent()?.attendees||[]).filter(a=>!a.isRelative) }\nfunction seatRelAtts() { return (seatEvent()?.attendees||[]).filter(a=>a.isRelative) }\n\nfunction seatedIds(){\n  const s=seatEvent()?.seating||{}; const ids=new Set()\n  Object.values(s).forEach(arr=>arr?.forEach(id=>ids.add(id))); return ids\n}\nfunction unassignedVips()  { const si=seatedIds(); return seatMainAtts().filter(a=>!si.has(a.id)) }\nfunction unassignedExtra() { const si=seatedIds(); return seatRelAtts().filter(a=>!si.has(a.id)) }\n\nfunction filteredForPicker(){\n  const q=S.seatSearch.trim(); const ua=unassignedVips()\n  return q ? ua.filter(a=>a.name.includes(q)||(a.title||'').includes(q)) : ua\n}\nfunction filteredExtraForPicker(){\n  const q=S.seatSearch.trim(); const ua=unassignedExtra()\n  return q ? ua.filter(a=>a.name.includes(q)) : ua\n}\n\nfunction getVipName(id){\n  for(const ev of S.events){ const a=(ev.attendees||[]).find(a=>a.id===id); if(a) return a.name }\n  return '（已刪除）'\n}\nfunction getVipRelatives(id,ev){\n  const event=ev||seatEvent()\n  return (event?.attendees||[]).filter(a=>a.isRelative&&a.sponsorId===id)\n}\nfunction tableDesc(e){\n  const p=[]\n  if(e.tables.main.seats)         p.push(`主桌 ${e.tables.main.seats} 位`)\n  if(e.tables.abbot.seats)        p.push(`住持桌 ${e.tables.abbot.seats} 位`)\n  if(e.tables.regular.length>0)   p.push(`${e.tables.regular.length} 桌一般桌`)\n  return p.join(' · ')\n}\nfunction totalSeats(e){\n  const main=(Number(e.tables?.main?.seats)||0)\n  const abbot=(Number(e.tables?.abbot?.seats)||0)\n  const reg=(e.tables?.regular||[]).reduce((s,t)=>s+(Number(t.seats)||0),0)\n  return main+abbot+reg\n}\n\n// ═══════════════════════════════════════════════════════\n// 初始化\n// ═══════════════════════════════════════════════════════\nfunction init(){\n  S.events = Storage.getEvents().map(normalizeEvent)\n  renderNav()\n  render()\n  document.getElementById('excel-input').addEventListener('change', handleExcelUpload)\n}\n\nfunction normalizeEvent(e){\n  return {\n    ...e,\n    subtitle: e.subtitle||'',\n    attendees: Array.isArray(e.attendees)&&e.attendees.length>0&&typeof e.attendees[0]==='object'\n      ? e.attendees : [],\n    seating: e.seating||{},\n  }\n}\n\nfunction emptyEventForm(){\n  return { name:'', subtitle:'', date:'', tables:{ main:{seats:''}, abbot:{tableNo:'',seats:''}, regular:[] } }\n}\n\n// ═══════════════════════════════════════════════════════\n// 渲染主框架\n// ═══════════════════════════════════════════════════════\nfunction render(){\n  const pc=document.getElementById('page-content')\n  switch(S.tab){\n    case 'events':   pc.innerHTML=renderEvents(); break\n    case 'seating':  pc.innerHTML=renderSeating(); break\n    case 'result':   pc.innerHTML=renderResult(); break\n    case 'settings': pc.innerHTML=renderSettings(); break\n  }\n  updateNavActive()\n  attachPageListeners()\n}\n\nfunction setTab(t){ S.tab=t; render() }\n\nfunction renderNav(){\n  const tabs=[\n    {id:'events',  label:'活動管理', icon:'<rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\"/><line x1=\"16\" y1=\"2\" x2=\"16\" y2=\"6\"/><line x1=\"8\" y1=\"2\" x2=\"8\" y2=\"6\"/><line x1=\"3\" y1=\"10\" x2=\"21\" y2=\"10\"/>'},\n    {id:'seating', label:'排桌',    icon:'<rect x=\"3\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/>'},\n    {id:'result',  label:'結果',    icon:'<path d=\"M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z\"/><polyline points=\"14 2 14 8 20 8\"/><line x1=\"16\" y1=\"13\" x2=\"8\" y2=\"13\"/><line x1=\"16\" y1=\"17\" x2=\"8\" y2=\"17\"/>'},\n    {id:'settings',label:'設定',    icon:'<circle cx=\"12\" cy=\"12\" r=\"3\"/><path d=\"M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z\"/>'},\n  ]\n  document.getElementById('bottom-tab').innerHTML = tabs.map(t=>`\n    <button class=\"tab-btn${S.tab===t.id?' active':''}\" onclick=\"setTab('${t.id}')\">\n      <svg viewBox=\"0 0 24 24\">${t.icon}</svg>\n      <span>${t.label}</span>\n    </button>`).join('')\n}\n\nfunction updateNavActive(){\n  document.querySelectorAll('.tab-btn').forEach(b=>{\n    const id=b.getAttribute('onclick').match(/'(\\w+)'/)?.[1]\n    b.classList.toggle('active', id===S.tab)\n  })\n}\n\nfunction attachPageListeners(){\n  // 搜尋輸入即時更新 picker（由 openSeatPicker 設定）\n}\n\n// ═══════════════════════════════════════════════════════\n// 活動管理頁\n// ═══════════════════════════════════════════════════════\nfunction renderEvents(){\n  const cards = S.events.map(e=>{\n    const ts=totalSeats(e)\n    const atLen=e.attendees.filter(a=>!a.isRelative).length\n    const relLen=e.attendees.filter(a=>a.isRelative).length\n    let meta=[]\n    if(e.date) meta.push(fmt(e.date))\n    if(tableDesc(e)) meta.push(fmt(tableDesc(e)))\n    if(e.attendees.length>0){\n      let s=`名單 ${atLen} 人`\n      if(relLen>0) s+=` + 親眷 ${relLen}`\n      meta.push(s)\n    }\n    if(ts>0) meta.push(`<span style=\"color:#6b3d2e;font-weight:500;\">可安排 ${ts} 人</span>`)\n    return `\n      <div class=\"event-card\">\n        <div class=\"event-card-main\">\n          <div class=\"vip-name\">${fmt(e.name)}</div>\n          ${e.subtitle?`<div style=\"font-size:13px;color:#a07060;margin-top:1px;\">${fmt(e.subtitle)}</div>`:''}\n          <div class=\"vip-meta\">${meta.join(' · ')}</div>\n        </div>\n        <button class=\"event-card-upload\" onclick=\"triggerUpload('${e.id}')\">上傳名單</button>\n        <button class=\"event-card-edit\" onclick=\"openEditEvent('${e.id}')\">\n          <svg width=\"20\" height=\"20\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n            <circle cx=\"12\" cy=\"12\" r=\"3\"/><path d=\"M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z\"/>\n          </svg>\n        </button>\n      </div>`\n  }).join('')\n  return `\n    ${cards||'<div style=\"color:#bbb;text-align:center;padding:40px 0;font-size:15px;\">尚未建立任何活動<br><br>點右下角 ＋ 新增活動</div>'}\n    <button class=\"fab\" onclick=\"openAddEvent()\">＋</button>`\n}\n\n// ═══════════════════════════════════════════════════════\n// 活動 Modal\n// ═══════════════════════════════════════════════════════\nfunction openAddEvent(){\n  S.editingEventId=null\n  S.tableInputMode='single'\n  openModal(renderEventModal(emptyEventForm()))\n}\n\nfunction openEditEvent(id){\n  const e=S.events.find(ev=>ev.id===id); if(!e) return\n  S.editingEventId=id\n  S.tableInputMode='single'\n  openModal(renderEventModal({\n    name:e.name, subtitle:e.subtitle||'', date:e.date||'',\n    tables:{ main:{seats:e.tables.main.seats||''}, abbot:{tableNo:e.tables.abbot.tableNo||'',seats:e.tables.abbot.seats||''}, regular:e.tables.regular.map(t=>({...t})) }\n  }))\n}\n\nfunction renderEventModal(f){\n  const isEdit=!!S.editingEventId\n  const regRows=(f.tables.regular||[]).map((t,i)=>`\n    <div class=\"table-item\">\n      <span class=\"table-item-info\">第 ${fmt(t.tableNo)} 桌 · ${fmt(t.seats)} 位</span>\n      <button class=\"relative-remove\" onclick=\"removeRegularTable(${i})\">×</button>\n    </div>`).join('')\n  const singleMode=S.tableInputMode==='single'\n  return `\n    <div class=\"modal-header\">\n      <button class=\"modal-action\" onclick=\"closeModal()\">${isEdit?'取消':'取消'}</button>\n      <span class=\"modal-title\">${isEdit?'編輯活動':'新增活動'}</span>\n      <button class=\"modal-action confirm\" onclick=\"saveEvent()\">儲存</button>\n    </div>\n    <div class=\"modal-body\">\n      <div class=\"form-group\">\n        <label class=\"form-label\">活動名稱 *</label>\n        <input id=\"ef-name\" class=\"form-input\" value=\"${fmt(f.name)}\" placeholder=\"例：2026 夏季學界禪七\">\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">活動屬性</label>\n        <input id=\"ef-subtitle\" class=\"form-input\" value=\"${fmt(f.subtitle)}\" placeholder=\"例：功德午宴\">\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">活動日期</label>\n        <input id=\"ef-date\" class=\"form-input\" type=\"date\" value=\"${fmt(f.date)}\">\n      </div>\n      <div class=\"section-divider\">桌次設定</div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">主桌</label>\n        <div class=\"table-setting-row\">\n          <span class=\"table-setting-label\">座位數</span>\n          <input id=\"ef-main-seats\" class=\"table-num-input\" type=\"number\" min=\"1\" value=\"${fmt(f.tables.main.seats)}\" placeholder=\"例：0\">\n        </div>\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">住持桌</label>\n        <div class=\"table-setting-row\">\n          <span class=\"table-setting-label\">桌號</span>\n          <input id=\"ef-abbot-no\" class=\"table-num-input\" type=\"number\" min=\"1\" value=\"${fmt(f.tables.abbot.tableNo)}\" placeholder=\"例：0\">\n          <span class=\"table-setting-label\" style=\"margin-left:8px;\">座位數</span>\n          <input id=\"ef-abbot-seats\" class=\"table-num-input\" type=\"number\" min=\"1\" value=\"${fmt(f.tables.abbot.seats)}\" placeholder=\"例：0\">\n        </div>\n      </div>\n      <div class=\"form-group\">\n        <label class=\"form-label\">一般桌</label>\n        <div id=\"regular-table-list\">${regRows}</div>\n        <div class=\"add-rel-form\">\n          <div style=\"display:flex;background:#e8ddd9;border-radius:8px;padding:3px;margin-bottom:12px;gap:3px;\">\n            <button style=\"flex:1;border:none;border-radius:6px;padding:7px;font-size:14px;font-family:inherit;cursor:pointer;transition:all 0.15s;${singleMode?'background:#fff;font-weight:bold;color:#6b3d2e;':'background:transparent;color:#888;'}\"\n                    onclick=\"setTableMode('single')\">單桌</button>\n            <button style=\"flex:1;border:none;border-radius:6px;padding:7px;font-size:14px;font-family:inherit;cursor:pointer;transition:all 0.15s;${!singleMode?'background:#fff;font-weight:bold;color:#6b3d2e;':'background:transparent;color:#888;'}\"\n                    onclick=\"setTableMode('range')\">批次範圍</button>\n          </div>\n          ${singleMode?`\n            <div class=\"table-setting-row\" style=\"margin-bottom:0;\">\n              <span class=\"table-setting-label\">桌號</span>\n              <input id=\"ef-new-no\" class=\"table-num-input\" type=\"number\" min=\"1\" placeholder=\"例：0\">\n              <span class=\"table-setting-label\" style=\"margin-left:8px;\">座位數</span>\n              <input id=\"ef-new-seats\" class=\"table-num-input\" type=\"number\" min=\"1\" placeholder=\"例：0\">\n            </div>\n            <button class=\"add-rel-btn\" onclick=\"addSingleTable()\">＋ 新增一般桌</button>\n          `:`\n            <div class=\"table-setting-row\" style=\"margin-bottom:10px;\">\n              <span class=\"table-setting-label\">從第</span>\n              <input id=\"ef-from\" class=\"table-num-input\" type=\"number\" min=\"1\" placeholder=\"例：5\">\n              <span class=\"table-setting-label\" style=\"margin-left:4px;\">至第</span>\n              <input id=\"ef-to\" class=\"table-num-input\" type=\"number\" min=\"1\" placeholder=\"例：10\">\n              <span style=\"font-size:14px;color:#666;margin-left:4px;\">桌</span>\n            </div>\n            <div class=\"table-setting-row\" style=\"margin-bottom:0;\">\n              <span class=\"table-setting-label\">每桌</span>\n              <input id=\"ef-range-seats\" class=\"table-num-input\" type=\"number\" min=\"1\" placeholder=\"例：10\">\n              <span style=\"font-size:14px;color:#666;margin-left:4px;\">位</span>\n            </div>\n            <button class=\"add-rel-btn\" onclick=\"addRangeTable()\">＋ 批次新增</button>\n          `}\n        </div>\n      </div>\n      ${isEdit?`<button class=\"btn-primary\" style=\"width:100%;background:#c0392b;margin-top:8px;\" onclick=\"deleteEvent('${S.editingEventId}')\">刪除此活動</button>`:''}\n    </div>`\n}\n\nfunction getCurrentFormTables(){\n  const regItems=document.querySelectorAll('#regular-table-list .table-item')\n  const regular=[]\n  regItems.forEach(item=>{\n    const text=item.querySelector('.table-item-info').textContent\n    const m=text.match(/第\\s*(\\S+)\\s*桌\\s*·\\s*(\\S+)\\s*位/)\n    if(m) regular.push({tableNo:m[1],seats:Number(m[2])})\n  })\n  return regular\n}\n\nfunction setTableMode(mode){\n  S.tableInputMode=mode\n  // Re-render the modal with current form values\n  const f={\n    name:document.getElementById('ef-name')?.value||'',\n    subtitle:document.getElementById('ef-subtitle')?.value||'',\n    date:document.getElementById('ef-date')?.value||'',\n    tables:{\n      main:{seats:document.getElementById('ef-main-seats')?.value||''},\n      abbot:{tableNo:document.getElementById('ef-abbot-no')?.value||'',seats:document.getElementById('ef-abbot-seats')?.value||''},\n      regular:getCurrentFormTables()\n    }\n  }\n  document.getElementById('modal-box').innerHTML=renderEventModal(f)\n}\n\nfunction addSingleTable(){\n  const no=document.getElementById('ef-new-no')?.value\n  const seats=document.getElementById('ef-new-seats')?.value\n  if(!no||!seats) return\n  const reg=getCurrentFormTables()\n  if(!reg.some(t=>Number(t.tableNo)===Number(no))){\n    reg.push({tableNo:no,seats:Number(seats)})\n  }\n  refreshRegularList(reg)\n  document.getElementById('ef-new-no').value=''\n  document.getElementById('ef-new-seats').value=''\n}\n\nfunction addRangeTable(){\n  const from=Number(document.getElementById('ef-from')?.value)\n  const to=Number(document.getElementById('ef-to')?.value)\n  const seats=document.getElementById('ef-range-seats')?.value\n  if(!from||!to||!seats||from>to) return\n  const reg=getCurrentFormTables()\n  for(let n=from;n<=to;n++){\n    if(!reg.some(t=>Number(t.tableNo)===n)) reg.push({tableNo:String(n),seats:Number(seats)})\n  }\n  refreshRegularList(reg)\n}\n\nfunction refreshRegularList(reg){\n  const el=document.getElementById('regular-table-list'); if(!el) return\n  el.innerHTML=reg.map((t,i)=>`\n    <div class=\"table-item\">\n      <span class=\"table-item-info\">第 ${fmt(t.tableNo)} 桌 · ${fmt(t.seats)} 位</span>\n      <button class=\"relative-remove\" onclick=\"removeRegularTable(${i})\">×</button>\n    </div>`).join('')\n}\n\nfunction removeRegularTable(idx){\n  const reg=getCurrentFormTables()\n  reg.splice(idx,1)\n  refreshRegularList(reg)\n}\n\nfunction saveEvent(){\n  const name=document.getElementById('ef-name')?.value?.trim()\n  if(!name){ alert('請填寫活動名稱'); return }\n  const tables={\n    main:{seats:Number(document.getElementById('ef-main-seats')?.value)||0},\n    abbot:{tableNo:Number(document.getElementById('ef-abbot-no')?.value)||0, seats:Number(document.getElementById('ef-abbot-seats')?.value)||0},\n    regular:getCurrentFormTables()\n  }\n  if(S.editingEventId){\n    const ev=S.events.find(e=>e.id===S.editingEventId); if(!ev) return\n    ev.name=name; ev.subtitle=document.getElementById('ef-subtitle')?.value?.trim()||''\n    ev.date=document.getElementById('ef-date')?.value||''; ev.tables=tables\n  } else {\n    S.events.push({\n      id:'ev_'+genId(), name, subtitle:document.getElementById('ef-subtitle')?.value?.trim()||'',\n      date:document.getElementById('ef-date')?.value||'', tables, attendees:[], seating:{}\n    })\n  }\n  Storage.saveEvents(S.events)\n  closeModal(); render()\n}\n\nfunction deleteEvent(id){\n  if(!confirm('確定要刪除此活動嗎？所有出席名單與排桌資料將一併刪除。')) return\n  S.events=S.events.filter(e=>e.id!==id)\n  if(S.seatEventId===id) S.seatEventId=null\n  if(S.resultEventId===id) S.resultEventId=null\n  Storage.saveEvents(S.events)\n  closeModal(); render()\n}\n\n// ═══════════════════════════════════════════════════════\n// Excel 上傳\n// ═══════════════════════════════════════════════════════\nfunction triggerUpload(evId){\n  S.uploadTargetId=evId\n  document.getElementById('excel-input').value=''\n  document.getElementById('excel-input').click()\n}\n\nfunction handleExcelUpload(e){\n  const file=e.target.files?.[0]; if(!file) return\n  const ev=S.events.find(ev=>ev.id===S.uploadTargetId); if(!ev) return\n  const reader=new FileReader()\n  reader.onload=evt=>{\n    try{\n      const wb=XLSX.read(evt.target.result,{type:'array'})\n      const ws=wb.Sheets[wb.SheetNames[0]]\n      const rows=XLSX.utils.sheet_to_json(ws,{header:1,defval:''})\n      const attendees=[]; let currentSponsor=null\n      for(let i=0;i<rows.length;i++){\n        const row=rows[i]\n        const name=String(row[3]||'').trim()\n        if(!name||name==='姓名') continue\n        const carNo=String(row[2]||'').trim()\n        const title=String(row[4]||'').trim()\n        const org=String(row[8]||'').trim()\n        const relFlag=String(row[10]||'').trim()\n        const isRelative=relFlag==='親眷'\n        const id='att_'+genId()\n        if(!isRelative){\n          const att={id,name,title,org,carNo,isRelative:false,sponsorId:null}\n          attendees.push(att); currentSponsor=att\n        } else {\n          attendees.push({id,name,title,org,carNo,isRelative:true,sponsorId:currentSponsor?.id||null})\n        }\n      }\n      ev.attendees=attendees; ev.seating={}\n      Storage.saveEvents(S.events)\n      const main=attendees.filter(a=>!a.isRelative).length\n      const rel=attendees.filter(a=>a.isRelative).length\n      alert(`上傳成功！正式貴賓 ${main} 人${rel?`，親眷 ${rel} 人`:''}`)\n      render()\n    }catch(err){ alert('讀取失敗：'+err.message) }\n  }\n  reader.readAsArrayBuffer(file)\n}\n\n// ═══════════════════════════════════════════════════════\n// 排桌頁\n// ═══════════════════════════════════════════════════════\nfunction renderSeating(){\n  if(!S.seatEventId || !seatEvent()){\n    const opts=S.events.map(e=>`<option value=\"${e.id}\">${fmt(e.name)}</option>`).join('')\n    return `\n      <div class=\"page-title\">排桌</div>\n      <select class=\"event-selector\" onchange=\"setSeatEvent(this.value)\">\n        <option value=\"\">請選擇活動…</option>${opts}\n      </select>\n      <div style=\"color:#bbb;text-align:center;padding:40px 0;font-size:14px;\">請先選擇活動</div>`\n  }\n  const ev=seatEvent()\n  let html=`\n    <div style=\"display:flex;align-items:center;gap:10px;margin-bottom:16px;\">\n      <select class=\"event-selector\" style=\"flex:1;margin-bottom:0;\" onchange=\"setSeatEvent(this.value)\">\n        ${S.events.map(e=>`<option value=\"${e.id}\"${e.id===S.seatEventId?' selected':''}>${fmt(e.name)}</option>`).join('')}\n      </select>\n    </div>`\n  // 主桌\n  if(ev.tables.main.seats){\n    const seating=ev.seating['main']||[]; const cap=Number(ev.tables.main.seats)\n    html+=renderSeatCard('main','主桌',seating,cap,ev)\n  }\n  // 住持桌\n  if(ev.tables.abbot.seats){\n    const no=ev.tables.abbot.tableNo; const seating=ev.seating['abbot']||[]; const cap=Number(ev.tables.abbot.seats)\n    html+=renderSeatCard('abbot',`住持桌${no?`（第 ${no} 桌）`:''}`,seating,cap,ev)\n  }\n  // 一般桌\n  ;(ev.tables.regular||[]).forEach(t=>{\n    const key=String(t.tableNo); const seating=ev.seating[key]||[]; const cap=Number(t.seats)\n    html+=renderSeatCard(key,`第 ${t.tableNo} 桌`,seating,cap,ev)\n  })\n  // 待分配\n  const ua=unassignedVips(); const ue=unassignedExtra()\n  html+=`<div class=\"seat-table-card\">\n    <div class=\"seat-table-header\">\n      <span class=\"seat-table-title\">待分配</span>\n      <span class=\"seat-count-text\">${ua.length+ue.length} 人</span>\n    </div>`\n  if(!ev.attendees.length){\n    html+=`<div style=\"color:#bbb;font-size:14px;text-align:center;padding:8px 0;\">尚未上傳名單，請至「活動管理」點「上傳名單」</div>`\n  } else if(!ua.length&&!ue.length){\n    html+=`<div style=\"color:#bbb;font-size:14px;text-align:center;padding:8px 0;\">所有出席者均已分配</div>`\n  } else {\n    html+='<div>'\n    ua.forEach(v=>{\n      html+=`<div style=\"padding:8px 0;border-bottom:1px solid #f5f5f5;\"><div style=\"font-size:15px;font-weight:bold;\">${fmt(v.name)}</div>`\n      ue.filter(ea=>ea.sponsorId===v.id).forEach(ea=>{\n        html+=`<div style=\"font-size:12px;color:#c09070;margin-top:3px;padding-left:6px;\">└ ${fmt(ea.name)}（親眷）</div>`\n      })\n      html+='</div>'\n    })\n    ue.filter(ea=>!ua.some(v=>v.id===ea.sponsorId)).forEach(ea=>{\n      html+=`<div style=\"padding:8px 0;border-bottom:1px solid #f5f5f5;\"><div style=\"font-size:15px;font-weight:bold;color:#c09070;\">${fmt(ea.name)}</div><div style=\"font-size:12px;color:#999;margin-top:2px;\">親眷</div></div>`\n    })\n    html+='</div>'\n  }\n  if(ev.tables.regular?.length>0&&(ua.length>0||ue.length>0)){\n    html+=`<button class=\"btn-primary\" style=\"width:100%;margin-top:14px;\" onclick=\"autoAssign()\">自動排入一般桌（親屬同桌）</button>`\n  }\n  html+='</div>'\n  return html\n}\n\nfunction renderSeatCard(key,title,seating,cap,ev){\n  const full=seating.length>=cap\n  let html=`<div class=\"seat-table-card\">\n    <div class=\"seat-table-header\">\n      <span class=\"seat-table-title\">${fmt(title)}</span>\n      <span class=\"seat-count-text\">${seating.length} / ${cap} 位</span>\n      ${full?'<span class=\"seat-full-badge\">已滿</span>':''}\n    </div>`\n  if(seating.length>0){\n    html+='<div class=\"seat-chips\">'\n    seating.forEach(vid=>{\n      const rels=getVipRelatives(vid,ev)\n      html+=`<div class=\"seat-chip\">\n        <div class=\"seat-chip-row\">\n          <span class=\"seat-chip-name\">${fmt(getVipName(vid))}</span>\n          <button class=\"seat-chip-remove\" onclick=\"removeFromTable('${vid}','${key}')\">×</button>\n        </div>\n        ${rels.length>0?`<div class=\"seat-chip-rel\">${rels.map(r=>fmt(r.name)).join('、')}</div>`:''}`\n      html+='</div>'\n    })\n    html+='</div>'\n  }\n  if(!full){\n    html+=`<button class=\"seat-assign-btn\" style=\"margin-top:10px;\" onclick=\"openSeatPicker('${key}')\">＋ 手動指派</button>`\n  }\n  html+='</div>'\n  return html\n}\n\nfunction setSeatEvent(id){\n  S.seatEventId=id||null; render()\n}\n\n// ═══════════════════════════════════════════════════════\n// 排桌邏輯\n// ═══════════════════════════════════════════════════════\nfunction doAssign(id,tableKey){\n  const s=seatEvent().seating\n  if(!s[tableKey]) s[tableKey]=[]\n  if(!s[tableKey].includes(id)) s[tableKey].push(id)\n}\n\nfunction removeFromTable(vid,tableKey){\n  const ev=seatEvent(); if(!ev) return\n  const s=ev.seating\n  if(s[tableKey]) s[tableKey]=s[tableKey].filter(id=>id!==vid)\n  Storage.saveEvents(S.events); render()\n}\n\nfunction openSeatPicker(tableKey){\n  S.seatPickTable=tableKey; S.batchPickIds=[]; S.seatSearch=''\n  openModal(renderSeatPickerModal())\n  setTimeout(()=>{\n    const inp=document.getElementById('seat-search-input')\n    if(inp) inp.addEventListener('input',e=>{ S.seatSearch=e.target.value; refreshPickerList() })\n  },0)\n}\n\nfunction renderSeatPickerModal(){\n  const tableLabel=S.seatPickTable==='main'?'指派到主桌':S.seatPickTable==='abbot'?'指派到住持桌':`指派到第 ${S.seatPickTable} 桌`\n  const hasBatch=S.batchPickIds.length>0\n  return `\n    <div class=\"modal-header\">\n      <button class=\"modal-action\" onclick=\"closeSeatPicker()\">取消</button>\n      <span class=\"modal-title\">${tableLabel}</span>\n      ${hasBatch?`<button class=\"modal-action confirm\" onclick=\"confirmBatch()\">確認（${S.batchPickIds.length} 人）</button>`:'<span style=\"min-width:52px;\"></span>'}\n    </div>\n    <div class=\"modal-body\">\n      <input id=\"seat-search-input\" class=\"attend-search\" placeholder=\"搜尋姓名…\" value=\"${fmt(S.seatSearch)}\">\n      <div id=\"picker-list\">${renderPickerList()}</div>\n    </div>`\n}\n\nfunction renderPickerList(){\n  const fp=filteredForPicker(); const fe=filteredExtraForPicker()\n  if(!fp.length&&!fe.length){\n    return `<div class=\"empty-hint\" style=\"padding:24px 0;\">${S.seatSearch?'找不到相符的出席者':'沒有待分配的出席者'}</div>`\n  }\n  let html=''\n  if(fp.length){\n    html+=`<div style=\"font-size:12px;font-weight:bold;color:#aaa;letter-spacing:0.5px;margin-bottom:6px;\">正式貴賓</div>`\n    fp.forEach(v=>{\n      const checked=S.batchPickIds.includes(v.id)\n      html+=`<div class=\"vip-check-row\" style=\"${checked?'background:#fdf3ee;':''}\" onclick=\"toggleBatch('${v.id}')\">\n        <div style=\"flex:1;\">\n          <div style=\"font-size:15px;font-weight:bold;\">${fmt(v.name)}</div>\n          ${v.title||v.org?`<div style=\"font-size:13px;color:#999;margin-top:2px;\">${[v.title,v.org].filter(Boolean).map(fmt).join(' · ')}</div>`:''}\n        </div>\n        <div style=\"width:24px;height:24px;border-radius:6px;border:2px solid;display:flex;align-items:center;justify-content:center;flex-shrink:0;${checked?'border-color:#6b3d2e;background:#6b3d2e;':'border-color:#ddd;'}\">\n          ${checked?'<svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"white\" stroke-width=\"3\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><polyline points=\"20,6 9,17 4,12\"/></svg>':''}\n        </div>\n      </div>`\n    })\n  }\n  if(fe.length){\n    html+=`<div style=\"font-size:12px;font-weight:bold;color:#aaa;letter-spacing:0.5px;margin-top:12px;margin-bottom:6px;\">隨行親眷</div>`\n    fe.forEach(ea=>{\n      const checked=S.batchPickIds.includes(ea.id)\n      html+=`<div class=\"vip-check-row\" style=\"${checked?'background:#fdf3ee;':''}\" onclick=\"toggleBatch('${ea.id}')\">\n        <div style=\"flex:1;\">\n          <div style=\"font-size:15px;font-weight:bold;\">${fmt(ea.name)}</div>\n          <div style=\"font-size:13px;color:#999;margin-top:2px;\">親眷</div>\n        </div>\n        <div style=\"width:24px;height:24px;border-radius:6px;border:2px solid;display:flex;align-items:center;justify-content:center;flex-shrink:0;${checked?'border-color:#6b3d2e;background:#6b3d2e;':'border-color:#ddd;'}\">\n          ${checked?'<svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"white\" stroke-width=\"3\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><polyline points=\"20,6 9,17 4,12\"/></svg>':''}\n        </div>\n      </div>`\n    })\n  }\n  return html\n}\n\nfunction refreshPickerList(){\n  const el=document.getElementById('picker-list'); if(!el) return\n  el.innerHTML=renderPickerList()\n  // update header confirm button\n  const hdr=document.querySelector('#modal-box .modal-header')\n  if(hdr){\n    const hasBatch=S.batchPickIds.length>0\n    const btnArea=hdr.querySelector('.modal-action.confirm,span[style]')\n    if(btnArea) btnArea.outerHTML=hasBatch\n      ?`<button class=\"modal-action confirm\" onclick=\"confirmBatch()\">確認（${S.batchPickIds.length} 人）</button>`\n      :'<span style=\"min-width:52px;\"></span>'\n  }\n}\n\nfunction toggleBatch(id){\n  const i=S.batchPickIds.indexOf(id)\n  if(i!==-1) S.batchPickIds.splice(i,1)\n  else S.batchPickIds.push(id)\n  refreshPickerList()\n}\n\nfunction confirmBatch(){\n  const key=S.seatPickTable\n  S.batchPickIds.forEach(id=>doAssign(id,key))\n  Storage.saveEvents(S.events)\n  closeSeatPicker(); render()\n}\n\nfunction closeSeatPicker(){ S.batchPickIds=[]; S.seatSearch=''; closeModal(); render() }\n\nfunction autoAssign(){\n  const ev=seatEvent(); if(!ev) return\n  const tables=ev.tables.regular; if(!tables.length) return\n  const s=ev.seating\n  const ua=[...unassignedVips()]; const ue=[...unassignedExtra()]\n  if(!ua.length&&!ue.length) return\n  // 主賓與其親眷配對\n  const groups=ua.map(v=>({\n    main:v,\n    extras:ue.filter(ea=>ea.sponsorId===v.id)\n  }))\n  // 孤立親眷\n  const orphans=ue.filter(ea=>!ua.some(v=>v.id===ea.sponsorId))\n  // 指派到一般桌\n  let tIdx=0\n  const assignNext=(id)=>{\n    while(tIdx<tables.length){\n      const t=tables[tIdx]; const key=String(t.tableNo)\n      if(!s[key]) s[key]=[]\n      if(s[key].length<Number(t.seats)){ doAssign(id,key); return true }\n      tIdx++\n    }\n    return false\n  }\n  groups.forEach(g=>{\n    // 找一個能放下主賓+親眷的桌子（盡量同桌）\n    const needed=1+g.extras.length\n    let placed=false\n    for(let i=tIdx;i<tables.length;i++){\n      const t=tables[i]; const key=String(t.tableNo)\n      if(!s[key]) s[key]=[]\n      const remain=Number(t.seats)-s[key].length\n      if(remain>=needed){\n        doAssign(g.main.id,key)\n        g.extras.forEach(ea=>doAssign(ea.id,key))\n        placed=true; break\n      }\n    }\n    if(!placed){\n      assignNext(g.main.id)\n      g.extras.forEach(ea=>assignNext(ea.id))\n    }\n  })\n  orphans.forEach(ea=>assignNext(ea.id))\n  Storage.saveEvents(S.events); render()\n}\n\n// ═══════════════════════════════════════════════════════\n// 結果頁\n// ═══════════════════════════════════════════════════════\nfunction renderResult(){\n  if(!S.resultEventId || !resultEvent()){\n    const opts=S.events.map(e=>`<option value=\"${e.id}\">${fmt(e.name)}</option>`).join('')\n    return `\n      <div class=\"page-title\">排桌結果</div>\n      <select class=\"event-selector\" onchange=\"setResultEvent(this.value)\">\n        <option value=\"\">請選擇活動…</option>${opts}\n      </select>\n      <div style=\"color:#bbb;text-align:center;padding:40px 0;font-size:14px;\">請先選擇活動</div>`\n  }\n  const ev=resultEvent()\n  let html=`\n    <select class=\"event-selector\" onchange=\"setResultEvent(this.value)\">\n      ${S.events.map(e=>`<option value=\"${e.id}\"${e.id===S.resultEventId?' selected':''}>${fmt(e.name)}</option>`).join('')}\n    </select>`\n  const tables=[]\n  if(ev.tables?.main?.seats&&ev.seating?.main?.length>0)\n    tables.push({key:'main',title:'主桌',seats:ev.tables.main.seats,ids:ev.seating.main})\n  if(ev.tables?.abbot?.seats&&ev.seating?.abbot?.length>0){\n    const no=ev.tables.abbot.tableNo?`（第 ${ev.tables.abbot.tableNo} 桌）`:''\n    tables.push({key:'abbot',title:`住持桌${no}`,seats:ev.tables.abbot.seats,ids:ev.seating.abbot})\n  }\n  ;(ev.tables?.regular||[]).forEach(t=>{\n    const k=String(t.tableNo)\n    if(ev.seating?.[k]?.length>0)\n      tables.push({key:k,title:`第 ${t.tableNo} 桌`,seats:t.seats,ids:ev.seating[k]})\n  })\n  if(!tables.length){\n    html+=`<div style=\"color:#bbb;text-align:center;padding:40px 0;font-size:14px;\">尚無排桌資料</div>`\n    return html\n  }\n  tables.forEach(t=>{\n    html+=`<div class=\"result-table-card\">\n      <div class=\"result-table-header\">\n        <span class=\"result-table-title\">${fmt(t.title)}</span>\n        <span class=\"result-table-count\">${t.ids.length} / ${t.seats} 位</span>\n      </div>`\n    t.ids.forEach(vid=>{\n      const att=(ev.attendees||[]).find(a=>a.id===vid)\n      const rels=getVipRelatives(vid,ev)\n      html+=`<div class=\"result-row\">\n        <div>\n          <div class=\"result-row-name\">${fmt(getVipName(vid))}</div>\n          ${att?.org||att?.title?`<div class=\"result-row-sub\">${[att.title,att.org].filter(Boolean).map(fmt).join(' · ')}</div>`:''}\n          ${rels.length>0?`<div style=\"font-size:12px;color:#c09070;margin-top:2px;\">${rels.map(r=>fmt(r.name)).join('、')}</div>`:''}\n        </div>\n        <button class=\"result-row-btn\" onclick=\"openSeatNote('${vid}','${fmt(t.title)}')\">座位小單</button>\n      </div>`\n    })\n    html+='</div>'\n  })\n  // 未分配\n  const allSeated=new Set(); Object.values(ev.seating||{}).forEach(arr=>arr?.forEach(id=>allSeated.add(id)))\n  const unassigned=(ev.attendees||[]).filter(a=>!allSeated.has(a.id))\n  if(unassigned.length>0){\n    html+=`<div class=\"result-table-card\">\n      <div class=\"result-table-header\" style=\"background:#aaa;\">\n        <span class=\"result-table-title\">未分配</span>\n        <span class=\"result-table-count\">${unassigned.length} 人</span>\n      </div>`\n    unassigned.forEach(a=>{\n      html+=`<div class=\"result-row\"><div class=\"result-row-name\">${fmt(a.name)}</div></div>`\n    })\n    html+='</div>'\n  }\n  // 複製文字按鈕\n  html+=`<button class=\"btn-primary\" style=\"width:100%;margin-top:8px;\" onclick=\"copyResultText()\">複製排桌文字</button>`\n  return html\n}\n\nfunction setResultEvent(id){ S.resultEventId=id||null; render() }\n\nfunction copyResultText(){\n  const ev=resultEvent(); if(!ev) return\n  const tables=[]\n  if(ev.tables?.main?.seats&&ev.seating?.main?.length>0)\n    tables.push({title:'主桌',seats:ev.tables.main.seats,ids:ev.seating.main})\n  if(ev.tables?.abbot?.seats&&ev.seating?.abbot?.length>0)\n    tables.push({title:'住持桌',seats:ev.tables.abbot.seats,ids:ev.seating.abbot})\n  ;(ev.tables?.regular||[]).forEach(t=>{\n    const k=String(t.tableNo); if(ev.seating?.[k]?.length>0)\n      tables.push({title:`第 ${t.tableNo} 桌`,seats:t.seats,ids:ev.seating[k]})\n  })\n  let text=`【${ev.name}${ev.subtitle?' '+ev.subtitle:''}】排桌結果\\n\\n`\n  tables.forEach(t=>{\n    text+=`■ ${t.title}（${t.ids.length} / ${t.seats} 位）\\n`\n    t.ids.forEach(id=>{ text+=`  ${getVipName(id)}\\n` })\n    text+='\\n'\n  })\n  navigator.clipboard.writeText(text).then(()=>alert('已複製到剪貼簿')).catch(()=>alert('複製失敗，請手動複製'))\n}\n\n// ═══════════════════════════════════════════════════════\n// 座位小單\n// ═══════════════════════════════════════════════════════\nfunction openSeatNote(vid,tableName){\n  const ev=resultEvent()\n  const att=(ev?.attendees||[]).find(a=>a.id===vid)\n  S.seatNoteData={\n    eventName:ev?.name||'', subtitle:ev?.subtitle||'',\n    name:att?.name||getVipName(vid), title:att?.title||'',\n    tableName, carNo:att?.carNo||''\n  }\n  showSeatNoteModal()\n}\n\nfunction showSeatNoteModal(){\n  const d=S.seatNoteData\n  document.getElementById('note-box').innerHTML=`\n    <div class=\"seat-note-top\">\n      <span>中台禪寺各精舍</span>\n    </div>\n    <div class=\"seat-note-event\">${fmt(d.eventName)}</div>\n    ${d.subtitle?`<div class=\"seat-note-subtitle\">${fmt(d.subtitle)}</div>`:''}\n    <div class=\"seat-note-divider\"></div>\n    <div class=\"seat-note-body\">\n      <div class=\"seat-note-label\">出席貴賓</div>\n      <div class=\"seat-note-value\">${fmt(d.name)}${d.title?` <span style=\"font-size:18px;color:#888;font-weight:400;\">${fmt(d.title)}</span>`:''}</div>\n      <div class=\"seat-note-divider\"></div>\n      <div style=\"margin-top:12px;\">\n        <div class=\"seat-note-label\">桌次</div>\n        <div class=\"seat-note-table\">${fmt(d.tableName)}</div>\n        ${d.carNo?`<div class=\"seat-note-carno\">車次：${fmt(d.carNo)}</div>`:''}\n      </div>\n    </div>\n    <div class=\"seat-note-actions\">\n      <button style=\"background:#f0e8e4;color:#6b3d2e;\" onclick=\"downloadSeatNote()\">下載圖片</button>\n      <button style=\"background:#6b3d2e;color:#fff;\" onclick=\"shareSeatNote()\">分享</button>\n      <button style=\"background:#eee;color:#666;\" onclick=\"closeSeatNote()\">關閉</button>\n    </div>`\n  document.getElementById('note-overlay').style.display='flex'\n}\n\nfunction closeSeatNote(){ document.getElementById('note-overlay').style.display='none' }\n\nasync function buildSeatNoteCanvas(d){\n  const font='\"Noto Sans TC\",\"Microsoft JhengHei\",\"PingFang TC\",sans-serif'\n  const W=600; const HEADER_H=70\n  let H=HEADER_H+18+34\n  if(d.subtitle) H+=6+28\n  H+=18+1+22+18+6+62\n  if(d.title) H+=8+26\n  H+=18+1+22+18+6+48\n  if(d.carNo) H+=10+24\n  H+=32\n  const dpr=Math.min(window.devicePixelRatio||2,3)\n  const canvas=document.createElement('canvas')\n  canvas.width=W*dpr; canvas.height=H*dpr\n  const ctx=canvas.getContext('2d')\n  ctx.scale(dpr,dpr)\n  ctx.textAlign='center'\n  ctx.fillStyle='#fff'; ctx.fillRect(0,0,W,H)\n  // Header\n  ctx.fillStyle='#ff7300'; ctx.fillRect(0,0,W,HEADER_H)\n  ctx.fillStyle='#fff'; ctx.font=`bold 24px ${font}`; ctx.textBaseline='middle'\n  ctx.fillText('中台禪寺各精舍',W/2,HEADER_H/2)\n  let y=HEADER_H; ctx.textBaseline='top'\n  // Event name\n  y+=18; ctx.fillStyle='#555'; ctx.font=`500 30px ${font}`\n  ctx.fillText(d.eventName,W/2,y); y+=34\n  if(d.subtitle){ y+=6; ctx.fillStyle='#a07060'; ctx.font=`24px ${font}`; ctx.fillText(d.subtitle,W/2,y); y+=28 }\n  // Divider 1\n  y+=18; ctx.fillStyle='#eee'; ctx.fillRect(20,y,W-40,1); y+=1+22\n  // Name\n  ctx.fillStyle='#aaa'; ctx.font=`bold 13px ${font}`; ctx.fillText('出席貴賓',W/2,y); y+=6\n  ctx.fillStyle='#2c2c2c'; ctx.font=`bold 52px ${font}`; ctx.fillText(d.name,W/2,y); y+=62\n  if(d.title){ ctx.fillStyle='#888'; ctx.font=`26px ${font}`; ctx.fillText(d.title,W/2,y); y+=8+26 }\n  // Divider 2\n  y+=18; ctx.fillStyle='#eee'; ctx.fillRect(20,y,W-40,1); y+=1+22\n  // Table\n  ctx.fillStyle='#aaa'; ctx.font=`bold 13px ${font}`; ctx.fillText('桌次',W/2,y); y+=6\n  ctx.fillStyle='#6b3d2e'; ctx.font=`bold 38px ${font}`; ctx.fillText(d.tableName,W/2,y); y+=48\n  if(d.carNo){ y+=10; ctx.fillStyle='#888'; ctx.font=`24px ${font}`; ctx.fillText(`車次：${d.carNo}`,W/2,y) }\n  return canvas\n}\n\nasync function downloadSeatNote(){\n  const d=S.seatNoteData; const canvas=await buildSeatNoteCanvas(d)\n  const a=document.createElement('a')\n  a.download=`座位小單_${d.name}.png`\n  a.href=canvas.toDataURL('image/png')\n  a.click()\n}\n\nasync function shareSeatNote(){\n  const d=S.seatNoteData; const canvas=await buildSeatNoteCanvas(d)\n  canvas.toBlob(async blob=>{\n    const file=new File([blob],`座位小單_${d.name}.png`,{type:'image/png'})\n    if(navigator.share&&navigator.canShare({files:[file]})){\n      try{ await navigator.share({files:[file],title:`座位小單 ${d.name}`}) }\n      catch(e){ if(e.name!=='AbortError') alert('分享失敗：'+e.message) }\n    } else { alert('此裝置不支援分享，請改用「下載圖片」') }\n  },'image/png')\n}\n\n// ═══════════════════════════════════════════════════════\n// 設定頁\n// ═══════════════════════════════════════════════════════\nfunction renderSettings(){\n  return `\n    <div style=\"padding:4px 0;\">\n      <div style=\"font-size:17px;font-weight:bold;color:#3d1f0f;margin-bottom:6px;\">雲端同步</div>\n      <div style=\"font-size:13px;color:#999;margin-bottom:16px;\">\n        資料自動儲存在部署此系統的 Google Drive 帳號，點下方按鈕即可同步。\n      </div>\n      <div style=\"background:#fff;border-radius:12px;padding:20px;margin-bottom:28px;box-shadow:0 1px 4px rgba(0,0,0,0.08);\">\n        <div style=\"display:flex;gap:10px;\">\n          <button class=\"btn-primary\" style=\"flex:1;background:#4a90d9;\" ${S.cloudSyncing?'disabled':''} onclick=\"cloudLoad()\">\n            ${S.cloudSyncing==='load'?'載入中…':'⬇ 從雲端載入'}\n          </button>\n          <button class=\"btn-primary\" style=\"flex:1;background:#27ae60;\" ${S.cloudSyncing?'disabled':''} onclick=\"cloudSave()\">\n            ${S.cloudSyncing==='save'?'儲存中…':'⬆ 儲存到雲端'}\n          </button>\n        </div>\n        ${S.cloudStatus?`<div style=\"color:${S.cloudStatus.startsWith('✓')?'#27ae60':'#c0392b'};font-size:13px;margin-top:10px;text-align:center;\">${fmt(S.cloudStatus)}</div>`:''}\n      </div>\n      <div style=\"font-size:17px;font-weight:bold;color:#3d1f0f;margin-bottom:6px;\">名單模板</div>\n      <div style=\"font-size:13px;color:#999;margin-bottom:16px;\">\n        下載 Excel 模板，填好後至各活動點「上傳名單」匯入。\n      </div>\n      <div style=\"background:#fff;border-radius:12px;padding:20px;margin-bottom:28px;box-shadow:0 1px 4px rgba(0,0,0,0.08);\">\n        <div style=\"font-size:13px;color:#555;margin-bottom:14px;line-height:1.8;\">\n          <div style=\"display:grid;grid-template-columns:auto 1fr;gap:4px 12px;\">\n            <span style=\"color:#aaa;\">C 欄</span><span>車次</span>\n            <span style=\"color:#aaa;\">D 欄</span><span>姓名（必填）</span>\n            <span style=\"color:#aaa;\">E 欄</span><span>法名</span>\n            <span style=\"color:#aaa;\">I 欄</span><span>護法會職稱</span>\n            <span style=\"color:#aaa;\">K 欄</span><span>填「親眷」代表隨行眷屬</span>\n          </div>\n        </div>\n        <button class=\"btn-primary\" style=\"width:100%;\" onclick=\"downloadTemplate()\">⬇ 下載名單模板（.xlsx）</button>\n      </div>\n      <div style=\"text-align:center;margin-top:24px;font-size:12px;color:#bbb;\">目前共 ${S.events.length} 個活動</div>\n    </div>`\n}\n\nfunction cloudLoad(){\n  if(!isGAS()){ S.cloudStatus='✗ 此功能僅在 Google Apps Script 部署版本中可用'; render(); return }\n  S.cloudSyncing='load'; S.cloudStatus=''; render()\n  google.script.run\n    .withSuccessHandler(function(result){\n      try{\n        const data=JSON.parse(result)\n        if(!Array.isArray(data.events)) throw new Error('資料格式錯誤')\n        if(!confirm(`雲端有 ${data.events.length} 個活動，確定要覆蓋本機資料嗎？`)){\n          S.cloudSyncing=''; render(); return\n        }\n        S.events=data.events.map(normalizeEvent)\n        Storage.saveEvents(S.events)\n        S.cloudStatus='✓ 已從雲端載入（'+new Date().toLocaleTimeString('zh-TW')+'）'\n      }catch(e){ S.cloudStatus='✗ 載入失敗：'+e.message }\n      S.cloudSyncing=''; render()\n    })\n    .withFailureHandler(function(err){ S.cloudStatus='✗ '+err.message; S.cloudSyncing=''; render() })\n    .gsLoad()\n}\n\nfunction cloudSave(){\n  if(!isGAS()){ S.cloudStatus='✗ 此功能僅在 Google Apps Script 部署版本中可用'; render(); return }\n  S.cloudSyncing='save'; S.cloudStatus=''; render()\n  const payload=JSON.stringify({events:S.events})\n  google.script.run\n    .withSuccessHandler(function(result){\n      try{\n        const r=JSON.parse(result)\n        if(!r.ok) throw new Error(r.error||'未知錯誤')\n        S.cloudStatus='✓ 已儲存到雲端（'+new Date().toLocaleTimeString('zh-TW')+'）'\n      }catch(e){ S.cloudStatus='✗ 儲存失敗：'+e.message }\n      S.cloudSyncing=''; render()\n    })\n    .withFailureHandler(function(err){ S.cloudStatus='✗ '+err.message; S.cloudSyncing=''; render() })\n    .gsSave(payload)\n}\n\nfunction isGAS(){ return typeof google!=='undefined'&&google.script&&google.script.run }\n\nfunction downloadTemplate(){\n  const rows=[\n    ['','卡號','車次','姓名','法名','','','','護法會職稱','','備註（親眷請填「親眷」）'],\n    ['','B001','小車 01','王大明','傳慧','','','','副會長','',''],\n    ['','B002','小車 01','王大明眷屬','','','','','','','親眷'],\n    ['','B003','大車 02','李小華','傳明','','','','委員','',''],\n    ['','B004','大車 02','李小華眷屬','','','','','','','親眷'],\n    ['','B005','小車 03','張三','傳智','','','','','',''],\n  ]\n  const ws=XLSX.utils.aoa_to_sheet(rows)\n  ws['!cols']=[{wch:4},{wch:8},{wch:10},{wch:12},{wch:10},{wch:4},{wch:4},{wch:4},{wch:14},{wch:4},{wch:18}]\n  const wb=XLSX.utils.book_new()\n  XLSX.utils.book_append_sheet(wb,ws,'貴賓名單')\n  XLSX.writeFile(wb,'貴賓名單模板.xlsx')\n}\n\n// ═══════════════════════════════════════════════════════\n// Modal 系統\n// ═══════════════════════════════════════════════════════\nfunction openModal(html){\n  document.getElementById('modal-box').innerHTML=html\n  document.getElementById('modal-overlay').style.display='flex'\n}\n\nfunction closeModal(){\n  document.getElementById('modal-overlay').style.display='none'\n  S.showEventModal=false; S.editingEventId=null\n}\n\nfunction handleModalOverlayClick(e){\n  if(e.target===document.getElementById('modal-overlay')) closeModal()\n}\n\ndocument.addEventListener('DOMContentLoaded',function(){\n  document.getElementById('modal-overlay').addEventListener('click',function(e){\n    if(e.target===this) closeModal()\n  })\n  document.getElementById('note-overlay').addEventListener('click',function(e){\n    if(e.target===this) closeSeatNote()\n  })\n})\n\n// ═══════════════════════════════════════════════════════\n// 啟動\n// ═══════════════════════════════════════════════════════\nwindow.addEventListener('DOMContentLoaded', init)\n</script>\n</body>\n</html>\n";
